#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 3e1 + 5;
int n, cna[MAXN], cnb[MAXN];
bool flag;
string s[5], t;
void dfs(int num)
{
	if (flag)return;
	if (num == 5)
	{
		for (int i = 1; i <= 26; ++i)
		{
			if (cna[i] > cnb[i])
			{
				return;
			}
		}
		flag = true;
		return;
	}
	for (auto c : s[num])
	{
		++cnb[c - 'A' + 1];
		dfs(num + 1);
		--cnb[c - 'A' + 1];
	}
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n = read();
	for (int i = 1; i <= 4; ++i)
	{
		cin >> s[i];
	}
	for (int i = 1; i <= n; ++i)
	{
		flag = false;
		memset(cna, 0, sizeof cna);
		cin >> t;
		for (auto c : t)
		{
			++cna[c - 'A' + 1];
		}
		dfs(1);
		if (flag)
		{
			puts("YES");
		}
		else
		{
			puts("NO");
		}
	}
	return false;
}
